package com.example.biometricapp;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;

import android.content.Intent;
import android.os.Bundle;
import android.provider.Settings;
import android.util.Log;
import android.view.View;
import android.widget.Button;
import android.widget.CompoundButton;
import android.widget.EditText;
import android.widget.Switch;
import android.widget.Toast;

import java.util.concurrent.Executor;

public class LoginActivity extends AppCompatActivity {

    private static final String TAG = "LoginActivity";

    private SharedPreferencesManager sharedPreferencesManager;
    private Executor executor;
    private BiometricPrompt biometricPrompt;
    private BiometricPrompt.PromptInfo promptInfo;

    private EditText usernameEditText;
    private EditText passwordEditText;
    private Button loginButton;
    private Switch biometricSwitch;
    private Button biometricLoginButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        sharedPreferencesManager = new SharedPreferencesManager(this);

        usernameEditText = findViewById(R.id.usernameEditText);
        passwordEditText = findViewById(R.id.passwordEditText);
        loginButton = findViewById(R.id.loginButton);
        biometricSwitch = findViewById(R.id.biometricSwitch);
        biometricLoginButton = findViewById(R.id.biometricLoginButton);

        // Initialize Biometric components
        executor = ContextCompat.getMainExecutor(this);
        biometricPrompt = new BiometricPrompt(LoginActivity.this,
                executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                Log.e(TAG, "Biometric authentication error: " + errString + " (" + errorCode + ")");
                // Handle specific errors
                if (errorCode == BiometricPrompt.ERROR_NO_BIOMETRICS ||
                    errorCode == BiometricPrompt.ERROR_HW_UNAVAILABLE ||
                    errorCode == BiometricPrompt.ERROR_SECURITY_UPDATE_NEEDED ||
                    errorCode == BiometricPrompt.ERROR_UNSUPPORTED) {
                    Toast.makeText(getApplicationContext(),
                            "Biometric hardware not available or configured. Please use password.",
                            Toast.LENGTH_LONG).show();
                    // Disable biometric login if hardware issues
                    sharedPreferencesManager.setBiometricEnabled(false);
                    biometricSwitch.setChecked(false);
                    updateUiForBiometricState(false);
                    showPasswordLoginUI(); // Ensure password fields are visible
                } else if (errorCode == BiometricPrompt.ERROR_USER_CANCELED ||
                           errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON) {
                    // User canceled or pressed negative button (password fallback)
                    Toast.makeText(getApplicationContext(), "Biometric canceled. Please use password.", Toast.LENGTH_SHORT).show();
                    showPasswordLoginUI();
                } else if (errorCode == BiometricPrompt.ERROR_NONE_ENROLLED) {
                    Toast.makeText(getApplicationContext(), "No biometrics enrolled. Please enroll one or use password.", Toast.LENGTH_LONG).show();
                    sharedPreferencesManager.setBiometricEnabled(false);
                    biometricSwitch.setChecked(false);
                    updateUiForBiometricState(false);
                    showPasswordLoginUI();
                }
                else {
                    Toast.makeText(getApplicationContext(), "Authentication error: " + errString, Toast.LENGTH_SHORT).show();
                    showPasswordLoginUI();
                }
            }

            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                Toast.makeText(getApplicationContext(), "Authentication Succeeded!", Toast.LENGTH_SHORT).show();
                navigateToMainActivity();
            }

            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
                Toast.makeText(getApplicationContext(), "Authentication Failed. Try again or use password.", Toast.LENGTH_SHORT).show();
                // The biometric prompt itself usually allows retries for failed attempts.
                // We do not automatically show password login here, as the user might retry on the prompt.
                // If they exhaust retries or cancel, onAuthenticationError will be triggered.
            }
        });

        promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Unlock App")
                .setSubtitle("Log in using your biometric credential")
                .setDescription("Touch the fingerprint sensor to authenticate.")
                .setNegativeButtonText("Use Password") // Fallback
                .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_WEAK | BiometricManager.Authenticators.DEVICE_CREDENTIAL) // BIOMETRIC_WEAK for fingerprint, face, etc. DEVICE_CREDENTIAL for pin/pattern/password fallback
                .build();


        loginButton.setOnClickListener(v -> {
            // Simulate password login
            String username = usernameEditText.getText().toString();
            String password = passwordEditText.getText().toString();
            if (username.equals("test") && password.equals("password")) { // Dummy credentials
                Toast.makeText(LoginActivity.this, "Password Login Successful!", Toast.LENGTH_SHORT).show();
                navigateToMainActivity();
            } else {
                Toast.makeText(LoginActivity.this, "Invalid credentials", Toast.LENGTH_SHORT).show();
            }
        });

        biometricSwitch.setOnCheckedChangeListener(new CompoundButton.OnCheckedChangeListener() {
            @Override
            public void onCheckedChanged(CompoundButton buttonView, boolean isChecked) {
                if (isChecked) {
                    // Check if biometrics are available before enabling
                    int canAuthenticate = checkBiometricCapability();
                    if (canAuthenticate == BiometricManager.BIOMETRIC_SUCCESS) {
                        sharedPreferencesManager.setBiometricEnabled(true);
                        updateUiForBiometricState(true);
                        Toast.makeText(LoginActivity.this, "Biometric login enabled", Toast.LENGTH_SHORT).show();
                    } else {
                        buttonView.setChecked(false); // Revert switch if not available
                        showBiometricError(canAuthenticate);
                        sharedPreferencesManager.setBiometricEnabled(false); // Ensure status is false
                    }
                } else {
                    sharedPreferencesManager.setBiometricEnabled(false);
                    updateUiForBiometricState(false);
                    Toast.makeText(LoginActivity.this, "Biometric login disabled", Toast.LENGTH_SHORT).show();
                }
            }
        });

        biometricLoginButton.setOnClickListener(v -> {
            if (sharedPreferencesManager.isBiometricEnabled()) {
                int canAuthenticate = checkBiometricCapability();
                if (canAuthenticate == BiometricManager.BIOMETRIC_SUCCESS) {
                    hidePasswordLoginUI(); // Hide password fields when showing biometric prompt
                    biometricPrompt.authenticate(promptInfo);
                } else {
                    showBiometricError(canAuthenticate);
                    sharedPreferencesManager.setBiometricEnabled(false);
                    biometricSwitch.setChecked(false);
                    updateUiForBiometricState(false);
                    showPasswordLoginUI(); // Ensure password UI is visible
                }
            } else {
                Toast.makeText(LoginActivity.this, "Biometric login is not enabled.", Toast.LENGTH_SHORT).show();
            }
        });
    }

    @Override
    protected void onResume() {
        super.onResume();
        // Update UI based on saved state and attempt biometric login if enabled
        boolean isBiometricEnabled = sharedPreferencesManager.isBiometricEnabled();
        biometricSwitch.setChecked(isBiometricEnabled);
        updateUiForBiometricState(isBiometricEnabled);

        if (isBiometricEnabled) {
            // Check biometric capability again just in case settings changed
            int canAuthenticate = checkBiometricCapability();
            if (canAuthenticate == BiometricManager.BIOMETRIC_SUCCESS) {
                hidePasswordLoginUI(); // Hide password fields while biometric prompt is active
                biometricPrompt.authenticate(promptInfo);
            } else {
                // If biometrics are enabled but now unavailable (e.g., user removed fingerprints)
                // disable the feature, inform user, and show password login.
                sharedPreferencesManager.setBiometricEnabled(false);
                biometricSwitch.setChecked(false);
                updateUiForBiometricState(false);
                showBiometricError(canAuthenticate);
                showPasswordLoginUI(); // Ensure password UI is visible if biometric fails pre-emptively
            }
        } else {
            showPasswordLoginUI();
        }
    }

    private void navigateToMainActivity() {
        Intent intent = new Intent(LoginActivity.this, MainActivity.class);
        startActivity(intent);
        finish(); // Prevent going back to login screen
    }

    private void updateUiForBiometricState(boolean isEnabled) {
        if (isEnabled) {
            biometricLoginButton.setVisibility(View.VISIBLE);
        } else {
            biometricLoginButton.setVisibility(View.GONE);
            // If biometric isn't enabled, ensure password login UI is visible.
            // This is called when the switch is toggled off.
            showPasswordLoginUI();
        }
    }

    private void showPasswordLoginUI() {
        usernameEditText.setVisibility(View.VISIBLE);
        passwordEditText.setVisibility(View.VISIBLE);
        loginButton.setVisibility(View.VISIBLE);
    }

    private void hidePasswordLoginUI() {
        usernameEditText.setVisibility(View.GONE);
        passwordEditText.setVisibility(View.GONE);
        loginButton.setVisibility(View.GONE);
    }


    private int checkBiometricCapability() {
        BiometricManager biometricManager = BiometricManager.from(this);
        // Using BIOMETRIC_WEAK as per promptInfo, and DEVICE_CREDENTIAL for fallback
        return biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_WEAK | BiometricManager.Authenticators.DEVICE_CREDENTIAL);
    }

    private void showBiometricError(int errorCode) {
        switch (errorCode) {
            case BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE:
                Toast.makeText(this, "No biometric hardware detected on this device.", Toast.LENGTH_LONG).show();
                break;
            case BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE:
                Toast.makeText(this, "Biometric hardware is currently unavailable.", Toast.LENGTH_LONG).show();
                break;
            case BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED:
                Toast.makeText(this, "No biometric credentials enrolled. Please enroll a fingerprint or face in device settings.", Toast.LENGTH_LONG).show();
                // Optionally, guide user to settings to enroll biometrics
                Intent enrollIntent = new Intent(Settings.ACTION_BIOMETRIC_ENROLL);
                enrollIntent.putExtra(Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED, BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.DEVICE_CREDENTIAL);
                // Check if there's an activity to handle the intent
                if (enrollIntent.resolveActivity(getPackageManager()) != null) {
                    startActivity(enrollIntent);
                } else {
                    Toast.makeText(this, "Cannot open biometric enrollment settings.", Toast.LENGTH_SHORT).show();
                }
                break;
            case BiometricManager.BIOMETRIC_ERROR_SECURITY_UPDATE_NEEDED:
                Toast.makeText(this, "Biometric system requires a security update.", Toast.LENGTH_LONG).show();
                break;
            case BiometricManager.BIOMETRIC_ERROR_UNSUPPORTED:
                Toast.makeText(this, "Biometric authentication is not supported on this device.", Toast.LENGTH_LONG).show();
                break;
            default:
                Toast.makeText(this, "An unknown biometric error occurred: " + errorCode, Toast.LENGTH_LONG).show();
                break;
        }
    }
}

